import { ref, watch, onMounted, onUnmounted } from 'vue'

type Theme = 'light' | 'dark' | 'system'

const theme = ref<Theme>((localStorage.getItem('theme') as Theme) || 'system')

const getSystemTheme = (): 'light' | 'dark' => {
  if (typeof window !== 'undefined' && window.matchMedia) {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'
  }
  return 'light'
}

const applyTheme = (val: Theme) => {
  const effectiveTheme = val === 'system' ? getSystemTheme() : val
  localStorage.setItem('theme', val)
  if (effectiveTheme === 'dark') {
    document.documentElement.classList.add('dark')
  } else {
    document.documentElement.classList.remove('dark')
  }
}

watch(theme, (val) => {
  applyTheme(val)
}, { immediate: true })

let mediaQueryListener: ((e: MediaQueryListEvent) => void) | null = null

export function useTheme() {
  const toggleTheme = () => {
    if (theme.value === 'light') {
      theme.value = 'dark'
    } else if (theme.value === 'dark') {
      theme.value = 'system'
    } else {
      theme.value = 'light'
    }
  }

  const isDark = () => {
    const effectiveTheme = theme.value === 'system' ? getSystemTheme() : theme.value
    return effectiveTheme === 'dark'
  }

  const getEffectiveTheme = (): 'light' | 'dark' => {
    return theme.value === 'system' ? getSystemTheme() : theme.value
  }

  onMounted(() => {
    if (typeof window !== 'undefined' && window.matchMedia) {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
      mediaQueryListener = (e: MediaQueryListEvent) => {
        if (theme.value === 'system') {
          applyTheme('system')
        }
      }
      mediaQuery.addEventListener('change', mediaQueryListener)
    }
  })

  onUnmounted(() => {
    if (mediaQueryListener && typeof window !== 'undefined' && window.matchMedia) {
      const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)')
      mediaQuery.removeEventListener('change', mediaQueryListener)
    }
  })

  return {
    theme,
    toggleTheme,
    isDark,
    getEffectiveTheme,
  }
}