<script setup lang="ts">
import { Server, X } from 'lucide-vue-next'
import { ref, onMounted, onUnmounted } from 'vue'
import PricingCard from '@/components/PricingCard.vue'
import AdvantageCard from '@/components/AdvantageCard.vue'
import SectionTitle from '@/components/SectionTitle.vue'
import { products } from '@/data/products'
import { ecsPricing } from '@/data/pricing'

const ecsProduct = products.find(p => p.id === 'ecs')!
const contactModalOpen = ref(false)

const heroRef = ref<HTMLElement | null>(null)
const advantageRef = ref<HTMLElement | null>(null)
const docRef = ref<HTMLElement | null>(null)
const pricingSectionRef = ref<HTMLElement | null>(null)

const isHeroVisible = ref(false)
const isAdvantageVisible = ref(false)
const isDocVisible = ref(false)
const isPricingVisible = ref(false)

let heroObserver: IntersectionObserver | null = null
let advantageObserver: IntersectionObserver | null = null
let docObserver: IntersectionObserver | null = null
let pricingObserver: IntersectionObserver | null = null

onMounted(() => {
  if (heroRef.value) {
    heroObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isHeroVisible.value = true
          } else {
            isHeroVisible.value = false
          }
        })
      },
      { threshold: 0.3 }
    )
    heroObserver.observe(heroRef.value)
  }

  if (advantageRef.value) {
    advantageObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isAdvantageVisible.value = true
          } else {
            isAdvantageVisible.value = false
          }
        })
      },
      { threshold: 0.2 }
    )
    advantageObserver.observe(advantageRef.value)
  }

  if (docRef.value) {
    docObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isDocVisible.value = true
          } else {
            isDocVisible.value = false
          }
        })
      },
      { threshold: 0.2 }
    )
    docObserver.observe(docRef.value)
  }

  if (pricingSectionRef.value) {
    pricingObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isPricingVisible.value = true
          } else {
            isPricingVisible.value = false
          }
        })
      },
      { threshold: 0.2 }
    )
    pricingObserver.observe(pricingSectionRef.value)
  }
})

onUnmounted(() => {
  if (heroObserver && heroRef.value) heroObserver.unobserve(heroRef.value)
  if (advantageObserver && advantageRef.value) advantageObserver.unobserve(advantageRef.value)
  if (docObserver && docRef.value) docObserver.unobserve(docRef.value)
  if (pricingObserver && pricingSectionRef.value) pricingObserver.unobserve(pricingSectionRef.value)
})

const docSections = [
  {
    title: '产品介绍',
    items: ['产品概述', '云服务计费模式', '云服务器类型'],
  },
  {
    title: '产品文档',
    items: ['建站教程', '控制台使用说明', 'API使用说明'],
  },
  {
    title: '常见问题',
    items: ['多类型主机的区别是什么？', '制作镜像注意事项', '云服务支持哪些操作系统'],
  },
]
</script>

<template>
  <div class="min-h-screen pt-12 lg:pt-14">
    <!-- Hero -->
    <section ref="heroRef" class="relative overflow-hidden">
      <div class="absolute inset-0">
        <img src="@/assets/images/banner-ecs.01b0f56f.png" alt="云服务器" class="w-full h-full object-cover" />
        <div class="absolute inset-0 bg-gradient-to-r from-black/50 via-black/30 to-transparent dark:from-dark-600/80 dark:via-dark-600/60"></div>
      </div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div class="max-w-3xl">
          <div :class="['flex items-center gap-3 mb-6 transition-all duration-700', isHeroVisible ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-10']">
            <div class="w-12 h-12 rounded-lg bg-white/10 flex items-center justify-center">
              <Server class="w-6 h-6 text-flame-500" />
            </div>
            <h1 class="text-3xl lg:text-4xl font-bold text-white">云服务器</h1>
          </div>
          <p :class="['text-white/80 text-lg leading-relaxed transition-all duration-700 delay-200', isHeroVisible ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-10']">
            安全可靠、秒级响应、弹性伸缩的计算服务，支持按实际使用的资源计费，有效降低 IT 成本，丰富机型可选，满足您的多样化业务需求
          </p>
        </div>
      </div>
    </section>

    <!-- Advantages -->
    <section ref="advantageRef" class="section-padding">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="产品优势" center :typing="isAdvantageVisible" />
        <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <AdvantageCard
            v-for="(adv, index) in ecsProduct.advantages"
            :key="adv.title"
            :icon="adv.icon"
            :title="adv.title"
            :description="adv.description"
            :is-visible="isAdvantageVisible"
            :index="index"
          />
        </div>
      </div>
    </section>

    <!-- Pricing -->
    <section ref="pricingSectionRef" class="section-padding bg-gray-50 dark:bg-dark-500/30">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="云服务器规格" subtitle="推荐购买" center :typing="isPricingVisible" />
        <div class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <PricingCard 
            v-for="(item, index) in ecsPricing" 
            :key="item.id" 
            :item="item" 
            :is-visible="isPricingVisible"
            :index="index"
            @open-contact-modal="contactModalOpen = true" 
          />
        </div>
      </div>
    </section>

    <!-- 联系我们弹窗 -->
    <Transition name="fade">
      <div v-if="contactModalOpen" class="fixed inset-0 z-50 flex items-center justify-center">
        <div class="absolute inset-0 bg-black/50 backdrop-blur-sm" @click="contactModalOpen = false"></div>
        <div class="relative bg-white dark:bg-dark-600 rounded-xl shadow-2xl p-6 max-w-sm w-full mx-4">
          <div class="flex items-center justify-between mb-6">
            <h3 class="text-xl font-bold text-gray-900 dark:text-white">联系我们</h3>
            <button
              @click="contactModalOpen = false"
              class="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 dark:text-gray-500 dark:hover:text-gray-300 transition-colors"
            >
              <X class="w-5 h-5" />
            </button>
          </div>
          <div class="flex flex-col items-center text-center space-y-4">
            <div class="relative group">
              <img src="@/assets/images/wechat2.jpg" alt="微信客服二维码" class="w-48 aspect-[3/4] object-contain rounded-lg border border-gray-200 dark:border-gray-700" />
            </div>
            <p class="text-gray-600 dark:text-gray-400 text-sm">扫码添加微信客服</p>
            <p class="text-gray-500 dark:text-gray-500 text-xs">工作时间: 7x24小时全天候服务</p>
          </div>
        </div>
      </div>
    </Transition>

    <!-- Documentation -->
    <section ref="docRef" class="section-padding">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="文档与工具" center :typing="isDocVisible" />
        <div class="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div 
            v-for="(section, index) in docSections" 
            :key="section.title" 
            :class="['glass-card p-6 transition-all duration-500', isDocVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10']"
            :style="{ transitionDelay: `${index * 100 + 200}ms` }"
          >
            <h3 class="text-gray-900 dark:text-white font-semibold mb-4">{{ section.title }}</h3>
            <ul class="space-y-2.5">
              <li v-for="item in section.items" :key="item">
                <a href="#" class="text-gray-500 hover:text-flame-500 dark:text-gray-400 dark:hover:text-flame-400 transition-colors text-sm flex items-center gap-2">
                  <span class="text-flame-500">-</span>
                  {{ item }}
                </a>
              </li>
            </ul>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>