<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue'
import { Users, Lightbulb, Heart, Shield } from 'lucide-vue-next'
import SectionTitle from '@/components/SectionTitle.vue'
import { animate, set } from 'animejs'

const whyChooseUs = [
  {
    icon: Users,
    title: '专业技术团队',
    items: ['深耕云计算领域多年的开发团队', '月月考核的五星级客服团队', '7X24小时的专业运维团队'],
  },
  {
    icon: Lightbulb,
    title: '推陈出新的探索精神',
    items: ['深入调研客户痛点', '了解企业的业务需求', '具备对行业的深刻洞察'],
  },
  {
    icon: Heart,
    title: '以客户为中心',
    items: ['快速响应客户需求', '提供面向未来的客户体验', '以提高客户满意度为目标'],
  },
  {
    icon: Shield,
    title: '秉承服务至上',
    items: ['端到端为客户提供服务', '采纳客户的智慧提升服务质量', '严格制定服务标准'],
  },
]

const heroSection = ref<HTMLElement | null>(null)
const aboutSection = ref<HTMLElement | null>(null)
const whyChooseSection = ref<HTMLElement | null>(null)
const cultureSection = ref<HTMLElement | null>(null)

const heroTitleChars = ref<string[]>([])
const heroSubtitleChars = ref<string[]>([])
const isHeroAnimating = ref(false)

let heroObserver: IntersectionObserver | null = null
let aboutObserver: IntersectionObserver | null = null
let whyChooseObserver: IntersectionObserver | null = null
let cultureObserver: IntersectionObserver | null = null

const animateHero = () => {
  if (!heroSection.value) return
  
  const heroContent = heroSection.value.querySelector('.hero-content')
  
  if (heroContent) {
    set(heroContent as HTMLElement, {
      opacity: 0,
      translateY: 50
    })
    
    animate(heroContent as HTMLElement, {
      opacity: [0, 1],
      translateY: [50, 0],
      duration: 1000,
      easing: 'easeOutCubic'
    })
  }
  
  heroTitleChars.value = '关于火焰云'.split('')
  heroSubtitleChars.value = '让上云变得更简单'.split('')
  
  setTimeout(() => {
    isHeroAnimating.value = true
  }, 100)
}

const animateAbout = () => {
  if (!aboutSection.value) return
  
  const paragraphs = aboutSection.value.querySelectorAll('.about-paragraph')
  
  paragraphs.forEach((p, index) => {
    set(p as HTMLElement, {
      opacity: 0,
      translateY: 30
    })
    
    animate(p as HTMLElement, {
      opacity: [0, 1],
      translateY: [30, 0],
      duration: 800,
      delay: index * 200,
      easing: 'easeOutCubic'
    })
  })
}

const animateWhyChoose = () => {
  if (!whyChooseSection.value) return
  
  const cards = whyChooseSection.value.querySelectorAll('.why-choose-card')
  
  cards.forEach((card, index) => {
    set(card as HTMLElement, {
      opacity: 0,
      translateY: 40,
      translateX: index % 2 === 0 ? -30 : 30
    })
    
    animate(card as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      translateX: [index % 2 === 0 ? -30 : 30, 0],
      duration: 800,
      delay: index * 150,
      easing: 'easeOutBack'
    })
  })
}

const animateCulture = () => {
  if (!cultureSection.value) return
  
  const cultureCard = cultureSection.value.querySelector('.culture-card')
  
  if (cultureCard) {
    set(cultureCard as HTMLElement, {
      opacity: 0,
      translateY: 40,
      scale: 0.95
    })
    
    animate(cultureCard as HTMLElement, {
      opacity: [0, 1],
      translateY: [40, 0],
      scale: [0.95, 1],
      duration: 900,
      easing: 'easeOutBack'
    })
  }
}

onMounted(() => {
  heroObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateHero()
        } else {
          isHeroAnimating.value = false
          heroTitleChars.value = []
          heroSubtitleChars.value = []
        }
      })
    },
    { threshold: 0.3 }
  )
  
  aboutObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateAbout()
        }
      })
    },
    { threshold: 0.2 }
  )
  
  whyChooseObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateWhyChoose()
        }
      })
    },
    { threshold: 0.2 }
  )
  
  cultureObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animateCulture()
        }
      })
    },
    { threshold: 0.3 }
  )
  
  if (heroSection.value) {
    heroObserver.observe(heroSection.value)
  }
  
  if (aboutSection.value) {
    aboutObserver.observe(aboutSection.value)
  }
  
  if (whyChooseSection.value) {
    whyChooseObserver.observe(whyChooseSection.value)
  }
  
  if (cultureSection.value) {
    cultureObserver.observe(cultureSection.value)
  }
})

onUnmounted(() => {
  if (heroObserver && heroSection.value) {
    heroObserver.unobserve(heroSection.value)
  }
  if (aboutObserver && aboutSection.value) {
    aboutObserver.unobserve(aboutSection.value)
  }
  if (whyChooseObserver && whyChooseSection.value) {
    whyChooseObserver.unobserve(whyChooseSection.value)
  }
  if (cultureObserver && cultureSection.value) {
    cultureObserver.unobserve(cultureSection.value)
  }
})
</script>

<template>
  <div class="min-h-screen pt-12 lg:pt-14">
    <!-- Hero -->
    <section ref="heroSection" class="relative overflow-hidden">
      <div class="absolute inset-0">
        <img src="@/assets/images/about-bg.9397bf66.png" alt="关于火焰云" class="w-full h-full object-cover" />
        <div class="absolute inset-0 bg-gradient-to-r from-black/50 via-black/30 to-transparent dark:from-dark-600/80 dark:via-dark-600/60"></div>
      </div>
      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div class="hero-content max-w-3xl">
          <h1 class="text-3xl lg:text-4xl font-bold text-white mb-4">
            <span
              v-for="(char, index) in heroTitleChars"
              :key="'hero-title-' + index"
              :class="['inline-block char-type', isHeroAnimating ? 'animate' : '']"
              :style="{ animationDelay: `${index * 50}ms` }"
            >{{ char }}</span>
          </h1>
          <p class="text-white/80 text-lg leading-relaxed">
            <span
              v-for="(char, index) in heroSubtitleChars"
              :key="'hero-subtitle-' + index"
              :class="['inline-block char-type-desc', isHeroAnimating ? 'animate' : '']"
              :style="{ animationDelay: `${(heroTitleChars.length + index) * 30}ms` }"
            >{{ char }}</span>
          </p>
        </div>
      </div>
    </section>

    <!-- About -->
    <section ref="aboutSection" class="section-padding">
      <div class="max-w-4xl mx-auto">
        <div class="prose prose-lg max-w-none">
          <p class="about-paragraph text-gray-600 dark:text-gray-300 leading-relaxed mb-4">
            2006年，自亚马逊第一次发布弹性云服务，再到2020年云计算的IT基建超越传统IT基建，云计算已经成为IT产业发展的趋势，也是新一代互联网、物联网、移动互联网的神经中枢。
          </p>
          <p class="about-paragraph text-gray-600 dark:text-gray-300 leading-relaxed mb-4">
            火焰云作为国内优质的IDC云计算综合服务提供商，专业提供互联网云计算、云安全、云存储及ICT解决方案等增值服务。深厚的基础架构，多年技术锤炼和海量服务经验，为客户提供高性能、易运维、智能化、弹性化的云服务。未来，火焰云将以"让上云变得更简单"为使命，通过技术创新和技术融合，为企业用户的数据架构实现云化智能重构和变革；通过大数据与产业经济的深度融合，推动行业数字化转型升级。
          </p>
          <p class="about-paragraph text-gray-600 dark:text-gray-300 leading-relaxed">
            目前服务的目标客户遍及中国大陆、美国、中国香港、新加坡、日本、中国台北、欧洲等国家和地区。
          </p>
        </div>
      </div>
    </section>

    <!-- Why Choose Us -->
    <section ref="whyChooseSection" class="section-padding bg-gray-50 dark:bg-dark-500/30">
      <div class="max-w-7xl mx-auto">
        <SectionTitle title="为什么选择火焰云" center />
        <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div v-for="item in whyChooseUs" :key="item.title" class="why-choose-card glass-card p-6">
            <div class="flex items-start gap-4">
              <div class="w-12 h-12 rounded-lg bg-flame-50 dark:bg-flame-500/10 flex items-center justify-center shrink-0">
                <component :is="item.icon" class="w-6 h-6 text-flame-500" />
              </div>
              <div>
                <h3 class="text-gray-900 dark:text-white font-semibold text-lg mb-3">{{ item.title }}</h3>
                <ul class="space-y-2">
                  <li v-for="li in item.items" :key="li" class="flex items-start gap-2 text-sm text-gray-600 dark:text-gray-300">
                    <span class="text-flame-500 mt-1">•</span>
                    <span>{{ li }}</span>
                  </li>
                </ul>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- Culture -->
    <section ref="cultureSection" class="section-padding relative overflow-hidden">
      <div class="absolute inset-0 opacity-30">
        <div class="absolute top-1/4 left-1/4 w-96 h-96 bg-flame-500/20 rounded-full blur-3xl"></div>
        <div class="absolute bottom-1/4 right-1/4 w-96 h-96 bg-blue-500/20 rounded-full blur-3xl"></div>
      </div>
      <div class="max-w-4xl mx-auto text-center relative">
        <SectionTitle title="企业文化" subtitle="Good To Great 从优秀到卓越" center />
        <div class="culture-card glass-card p-8 lg:p-12 mt-8">
          <p class="text-gray-600 dark:text-gray-300 text-lg leading-relaxed">
            让上云变得更简单
          </p>
          <p class="text-gray-500 dark:text-gray-400 mt-4">
            专业运维团队7X24小时在线支持上云，提供互联网云计算、云安全、云存储及ICT解决方案等增值服务
          </p>
        </div>
      </div>
    </section>
  </div>
</template>

<style scoped>
.char-type {
  opacity: 0;
  transform: translateY(-20px);
  filter: blur(4px);
}

.char-type.animate {
  animation: charReveal 0.4s ease-out forwards;
}

