<script setup lang="ts">
import { Shield, Scaling, Cloud, MousePointerClick, Wifi, Brain, Monitor, HardDrive, Coins, Map } from 'lucide-vue-next'
import { computed, type Component } from 'vue'

const props = defineProps<{
  icon: string
  title: string
  description: string
  isVisible?: boolean
  index?: number
}>()

const iconMap: Record<string, Component> = {
  Shield,
  Scaling,
  Cloud,
  MousePointerClick,
  Wifi,
  Brain,
  Monitor,
  HardDrive,
  Coins,
  Map,
}

const IconComponent = computed(() => iconMap[props.icon] || Shield)
</script>

<template>
  <div 
    :class="['glass-card p-6 text-center hover:bg-gray-50 dark:hover:bg-white/10 transition-all duration-300 group advantage-card-animate', isVisible ? 'animate-in' : '']"
    :style="isVisible ? { animationDelay: `${(index || 0) * 100}ms` } : {}"
  >
    <div class="w-14 h-14 rounded-xl bg-flame-50 dark:bg-flame-500/10 flex items-center justify-center mx-auto mb-4 group-hover:bg-flame-100 dark:group-hover:bg-flame-500/20 transition-colors">
      <component :is="IconComponent" class="w-7 h-7 text-flame-500" />
    </div>
    <h3 class="text-gray-900 dark:text-white font-semibold mb-2">{{ title }}</h3>
    <p class="text-gray-500 dark:text-gray-400 text-sm leading-relaxed">{{ description }}</p>
  </div>
</template>

<style scoped>
.advantage-card-animate {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.5s ease-out, transform 0.5s ease-out;
}

.advantage-card-animate.animate-in {
