<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted, nextTick, watch } from 'vue'
import { ChevronLeft, ChevronRight, Server, Globe, Database, X } from 'lucide-vue-next'
import { animate } from 'animejs'
import ProductCard from '@/components/ProductCard.vue'
import PricingCard from '@/components/PricingCard.vue'
import SectionTitle from '@/components/SectionTitle.vue'
import DeploymentShowcase from '@/components/DeploymentShowcase.vue'
import { products, industrySolutions, faqItems } from '@/data/products'
import { ecsPricing, cdnPricing, ossPricing } from '@/data/pricing'
import type { PricingItem } from '@/data/pricing'

const pricingTab = ref('ecs')
const industryTab = ref('education')
const openFaq = ref<string | null>(null)
const showQrCode = ref(false)
const contactModalOpen = ref(false)

const currentSolution = computed(() => industrySolutions.find(s => s.id === industryTab.value))
const currentSolutionIndex = computed(() => industrySolutions.findIndex(s => s.id === industryTab.value))

const pricingSectionRef = ref<HTMLElement | null>(null)
const isPricingSectionVisible = ref(false)
const industrySolutionRef = ref<HTMLElement | null>(null)
const isIndustrySolutionVisible = ref(false)
const globalCoverageRef = ref<HTMLElement | null>(null)
const isGlobalCoverageVisible = ref(false)
const coverageTitleChars = ref<string[]>([])
const coverageDescChars = ref<string[]>([])
const isCoverageAnimating = ref(false)

const faqSectionRef = ref<HTMLElement | null>(null)
const isFaqSectionVisible = ref(false)

const industrySectionRef = ref<HTMLElement | null>(null)
const isSectionActive = ref(false)
let isScrollingToSection = false
let observer: IntersectionObserver | null = null
let inertiaTimeout: ReturnType<typeof setTimeout> | null = null
let pricingObserver: IntersectionObserver | null = null
let industrySolutionObserver: IntersectionObserver | null = null
let globalCoverageObserver: IntersectionObserver | null = null
let faqSectionObserver: IntersectionObserver | null = null

const scrollToSectionCenter = () => {
  if (!industrySectionRef.value || isScrollingToSection) return
  
  isScrollingToSection = true
  const rect = industrySectionRef.value.getBoundingClientRect()
  const windowHeight = window.innerHeight
  const scrollY = window.scrollY
  const targetY = scrollY + rect.top - (windowHeight - rect.height) / 2
  
  window.scrollTo({
    top: targetY,
    behavior: 'smooth'
  })
  
  setTimeout(() => {
    isScrollingToSection = false
    isSectionActive.value = true
  }, 800)
}

const handleScrollEnd = () => {
  if (industrySectionRef.value && !isSectionActive.value) {
    const rect = industrySectionRef.value.getBoundingClientRect()
    const windowHeight = window.innerHeight
    const shouldSnap = rect.top < windowHeight * 0.8 && rect.bottom > windowHeight * 0.2
    
    if (shouldSnap) {
      scrollToSectionCenter()
    }
  }
}

const checkScrollEnd = () => {
  if (inertiaTimeout) clearTimeout(inertiaTimeout)
  inertiaTimeout = setTimeout(handleScrollEnd, 150)
}

onMounted(() => {
  if (industrySectionRef.value) {
    observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting && !isSectionActive.value) {
            checkScrollEnd()
          }
        })
      },
      { threshold: [0.3, 0.5, 0.7] }
    )
    observer.observe(industrySectionRef.value)
  }
  
  window.addEventListener('scroll', checkScrollEnd, { passive: true })
})

onUnmounted(() => {
  if (bannerTimer) clearInterval(bannerTimer)
  if (observer && industrySectionRef.value) {
    observer.unobserve(industrySectionRef.value)
  }
  if (pricingObserver && pricingSectionRef.value) {
    pricingObserver.unobserve(pricingSectionRef.value)
  }
  if (inertiaTimeout) clearTimeout(inertiaTimeout)
  window.removeEventListener('scroll', checkScrollEnd)
})

const pricingTabs = [
  { id: 'ecs', name: '云服务器', icon: Server },
  { id: 'cdn', name: 'CDN', icon: Globe },
  { id: 'oss', name: '对象存储', icon: Database },
]

const pricingDataMap: Record<string, PricingItem[]> = {
  ecs: ecsPricing,
  cdn: cdnPricing,
  oss: ossPricing,
}


const toggleFaq = (question: string) => {
  openFaq.value = openFaq.value === question ? null : question
}

import header201 from '@/assets/images/header-201.png'
import headerDdos2 from '@/assets/images/header-ddos2.png'
import headerJiedian2 from '@/assets/images/header-jiedian2.png'

import video1 from '@/assets/vids/local67ac084bde6ff.mp4'
import video2 from '@/assets/vids/local694e67e1b9ba9.mp4'
import video3 from '@/assets/vids/local6911e7b65b57f.mp4'

const banners = [
  {
    video: video1,
    image: header201,
    title: '新用户首购享免费福利',
    subtitle: '活动充值充200送100',
    description: '咨询专属销售客服立即领取活动福利',
  },
  {
    video: video2,
    image: headerDdos2,
    title: '玄武盾DDoS防护',
    subtitle: '全球安全加速服务',
    description: '毫秒级攻击响应、多维度行为分析及机器学习',
  },
  {
    video: video3,
    image: headerJiedian2,
    title: '全球多节点覆盖',
    subtitle: '30+云数据中心',
    description: '安全合规，基础设施遍布全球',
  },
]

const currentBanner = ref(0)
let bannerTimer: ReturnType<typeof setInterval> | null = null

const bannerTitleChars = ref<string[]>(banners[0].title.split(''))
const bannerSubtitleChars = ref<string[]>(banners[0].subtitle.split(''))
const bannerDescChars = ref<string[]>(banners[0].description.split(''))
const isBannerAnimating = ref(true)

const animateBannerText = () => {
  const banner = banners[currentBanner.value]
  const titleChars = banner.title.split('')
  const subtitleChars = banner.subtitle.split('')
  const descChars = banner.description.split('')
  
  bannerTitleChars.value = []
  bannerSubtitleChars.value = []
  bannerDescChars.value = []
  isBannerAnimating.value = false
  
  const bannerTitle = document.querySelector('.banner-title') as HTMLElement
  const bannerDesc = document.querySelector('.banner-desc') as HTMLElement
  
  if (bannerTitle) {
    bannerTitle.style.visibility = 'hidden'
    bannerTitle.style.minHeight = bannerTitle.offsetHeight + 'px'
    bannerTitle.style.visibility = 'visible'
  }
  
  if (bannerDesc) {
    bannerDesc.style.visibility = 'hidden'
    bannerDesc.style.minHeight = bannerDesc.offsetHeight + 'px'
    bannerDesc.style.visibility = 'visible'
  }
  
  setTimeout(() => {
    isBannerAnimating.value = true
    bannerTitleChars.value = titleChars
  }, 100)
  
  setTimeout(() => {
    bannerSubtitleChars.value = subtitleChars
  }, titleChars.length * 50 + 200)
  
  setTimeout(() => {
    bannerDescChars.value = descChars
  }, (titleChars.length + subtitleChars.length) * 50 + 400)
}

const startBannerTimer = () => {
  bannerTimer = setInterval(() => {
    currentBanner.value = (currentBanner.value + 1) % banners.length
  }, 5000)
}

const animationTypes = [
  { name: 'fadeIn', anim: (el: HTMLElement) => animate(el, { opacity: [0, 1], translateY: [20, 0], duration: 800, easing: 'easeOutQuad' }) },
  { name: 'slideUp', anim: (el: HTMLElement) => animate(el, { translateY: [50, 0], opacity: [0, 1], duration: 1000, easing: 'easeOutCubic' }) },
  { name: 'slideLeft', anim: (el: HTMLElement) => animate(el, { translateX: [-50, 0], opacity: [0, 1], duration: 900, easing: 'easeOutQuad' }) },
  { name: 'slideRight', anim: (el: HTMLElement) => animate(el, { translateX: [50, 0], opacity: [0, 1], duration: 900, easing: 'easeOutQuad' }) },
  { name: 'scaleIn', anim: (el: HTMLElement) => animate(el, { scale: [0.8, 1], opacity: [0, 1], duration: 700, easing: 'easeOutBack' }) },
  { name: 'rotateIn', anim: (el: HTMLElement) => animate(el, { rotate: [-15, 0], opacity: [0, 1], duration: 800, easing: 'easeOutQuad' }) },
]

const getRandomAnimation = () => {
  return animationTypes[Math.floor(Math.random() * animationTypes.length)]
}

const animateTextElements = () => {
  setTimeout(() => {
    const textElements = document.querySelectorAll('.animate-text')
    
    textElements.forEach((el, index) => {
      const animation = getRandomAnimation()
      const delay = index * 200 + Math.random() * 300
      
      setTimeout(() => {
        animation.anim(el as HTMLElement)
      }, delay)
    })
  }, 100)
}

const animateGlobalCoverageText = () => {
  setTimeout(() => {
    const textElements = document.querySelectorAll('.global-coverage-section .animate-text')
    
    textElements.forEach((el, index) => {
      const textEl = el as HTMLElement
      textEl.style.opacity = '0'
      textEl.style.transform = 'translateY(10px)'
      
      setTimeout(() => {
        animate(textEl, {
          opacity: [0, 1],
          translateY: [10, 0],
          duration: 500,
          easing: 'easeOutQuad'
        })
      }, index * 150)
    })
  }, 100)
}

const animateStatItems = () => {
  setTimeout(() => {
    const statItems = document.querySelectorAll('.stat-item-random')
    
    statItems.forEach((item) => {
      const statItem = item as HTMLElement
      const number = statItem.querySelector('.stat-number') as HTMLElement
      const label = statItem.querySelector('.stat-label') as HTMLElement
      
      if (number) {
        number.style.opacity = '0'
        number.style.transform = 'translateY(20px)'
      }
      
      if (label) {
        label.style.opacity = '0'
        label.style.transform = 'translateY(10px)'
      }
    })
    
    statItems.forEach((item, index) => {
      const statItem = item as HTMLElement
      const number = statItem.querySelector('.stat-number') as HTMLElement
      const label = statItem.querySelector('.stat-label') as HTMLElement
      
      const randomDelay = Math.random() * 300 + 100
      const randomDuration = Math.random() * 400 + 400
      const randomEasing = ['easeOutBack', 'easeOutBounce', 'easeOutElastic'][Math.floor(Math.random() * 3)]
      
      setTimeout(() => {
        if (number) {
          animate(number, {
            opacity: [0, 1],
            translateY: [20, 0],
            scale: [0.8, 1],
            duration: randomDuration,
            easing: randomEasing as any
          })
        }
        
        if (label) {
          setTimeout(() => {
            animate(label, {
              opacity: [0, 1],
              translateY: [10, 0],
              duration: randomDuration * 0.8,
              easing: 'easeOutQuad'
            })
          }, 100)
        }
      }, index * 200 + randomDelay)
    })
  }, 200)
}

const animateFaqSection = () => {
  setTimeout(() => {
    const faqSection = faqSectionRef.value
    if (!faqSection) return
    
    const title = faqSection.querySelector('.faq-title') as HTMLElement
    const subtitle = faqSection.querySelector('.faq-subtitle') as HTMLElement
    const faqItems = faqSection.querySelectorAll('.faq-item-animate')
    
    if (title) {
      title.style.opacity = '0'
      title.style.transform = 'translateY(30px)'
      
      setTimeout(() => {
        animate(title, {
          opacity: [0, 1],
          translateY: [30, 0],
          duration: 600,
          easing: 'easeOutBack'
        })
      }, 100)
    }
    
    if (subtitle) {
      subtitle.style.opacity = '0'
      subtitle.style.transform = 'translateY(20px)'
      
      setTimeout(() => {
        animate(subtitle, {
          opacity: [0, 1],
          translateY: [20, 0],
          duration: 500,
          easing: 'easeOutQuad'
        })
      }, 200)
    }
    
    faqItems.forEach((item, index) => {
      const faqItem = item as HTMLElement
      const startX = index % 2 === 0 ? -30 : 30
      faqItem.style.opacity = '0'
      faqItem.style.transform = `translateX(${startX}px)`
      
      const randomDelay = Math.random() * 200 + 100
      const randomDuration = Math.random() * 300 + 400
      
      setTimeout(() => {
        animate(faqItem, {
          opacity: [0, 1],
          translateX: [startX, 0],
          duration: randomDuration,
          easing: 'easeOutBack'
        })
      }, 400 + index * 100 + randomDelay)
    })
  }, 100)
}

const animatePricingCards = () => {
  setTimeout(() => {
    const cardElements = document.querySelectorAll('.pricing-card-animate')
    
    cardElements.forEach((el) => {
      const element = el as HTMLElement
      element.style.opacity = '0'
      element.style.transform = 'translateY(30px) scale(0.9)'
    })
    
    cardElements.forEach((el, index) => {
      const delay = index * 100
      
      setTimeout(() => {
        animate(el as HTMLElement, {
          opacity: [0, 1],
          translateY: [30, 0],
          scale: [0.9, 1],
          duration: 600,
          easing: 'easeOutBack'
        })
      }, delay)
    })
  }, 100)
}

const animateSolutionSection = () => {
  setTimeout(() => {
    const solutionItems = document.querySelectorAll('.solution-item-animate')
    const solutionContent = document.querySelector('.solution-content-animate')
    
    solutionItems.forEach((el, index) => {
      const element = el as HTMLElement
      element.style.opacity = '0'
      element.style.transform = 'translateX(-30px)'
    })
    
    solutionItems.forEach((el, index) => {
      const delay = index * 100
      
      setTimeout(() => {
        animate(el as HTMLElement, {
          opacity: [0, 1],
          translateX: [-30, 0],
          duration: 500,
          easing: 'easeOutBack'
        })
      }, delay)
    })
    
    if (solutionContent) {
      const contentEl = solutionContent as HTMLElement
      contentEl.style.opacity = '0'
      contentEl.style.transform = 'scale(0.95)'
      contentEl.style.filter = 'blur(4px)'
      
      setTimeout(() => {
        animate(contentEl, {
          opacity: [0, 1],
          scale: [0.95, 1],
          filter: [4, 0],
          duration: 500,
          easing: 'easeOutQuad'
        })
        
        setTimeout(() => {
          contentEl.style.filter = ''
        }, 500)
      }, 300)
      
      const featureSpans = solutionContent.querySelectorAll('.solution-feature-animate')
      featureSpans.forEach((el, index) => {
        const spanEl = el as HTMLElement
        spanEl.style.opacity = '0'
        spanEl.style.transform = 'translateY(10px)'
      })
      
      featureSpans.forEach((el, index) => {
        const delay = index * 100
        
        setTimeout(() => {
          animate(el as HTMLElement, {
            opacity: [0, 1],
            translateY: [10, 0],
            duration: 400,
            easing: 'easeOutBack'
          })
        }, 600 + delay)
      })
    }
  }, 100)
}

const animateGlobalCoverage = () => {
  setTimeout(() => {
    const coverageSection = document.querySelector('.global-coverage-title')
    const imageContainer = document.querySelector('.coverage-image-animate')
    
    if (coverageSection) {
      const titleEl = coverageSection as HTMLElement
      titleEl.style.opacity = '0'
      titleEl.style.transform = 'translateY(-20px)'
      
      setTimeout(() => {
        animate(titleEl, {
          opacity: [0, 1],
          translateY: [-20, 0],
          duration: 600,
          easing: 'easeOutQuad'
        })
      }, 100)
    }
    
    if (imageContainer) {
      const imgEl = imageContainer as HTMLElement
      imgEl.style.opacity = '0'
      imgEl.style.transform = 'scale(1.05)'
      
      setTimeout(() => {
        animate(imgEl, {
          opacity: [0, 1],
          scale: [1.05, 1],
          duration: 800,
          easing: 'easeOutQuad'
        })
      }, 800)
    }
  }, 100)
}

const animateProductCards = () => {
  setTimeout(() => {
    const cardElements = document.querySelectorAll('.product-card-animate')
    
    cardElements.forEach((el, index) => {
      const delay = index * 80
      
      setTimeout(() => {
        animate(el as HTMLElement, {
          opacity: [0, 1],
          translateX: [-20, 0],
          duration: 500,
          easing: 'easeOutQuad'
        })
      }, delay)
    })
  }, 300)
}

const prevBanner = () => {
  currentBanner.value = (currentBanner.value - 1 + banners.length) % banners.length
  resetBannerTimer()
}

const nextBanner = () => {
  currentBanner.value = (currentBanner.value + 1) % banners.length
  resetBannerTimer()
}

const resetBannerTimer = () => {
  if (bannerTimer) clearInterval(bannerTimer)
  startBannerTimer()
}

watch(currentBanner, () => {
  nextTick(() => {
    animateBannerText()
  })
})

watch(pricingTab, () => {
  nextTick(() => {
    animatePricingCards()
  })
})

watch(isPricingSectionVisible, (newVal) => {
  if (newVal) {
    nextTick(() => {
      animatePricingCards()
    })
  }
})

watch(isIndustrySolutionVisible, (newVal) => {
  if (newVal) {
    nextTick(() => {
      animateSolutionSection()
    })
  }
})

// watch(isGlobalCoverageVisible, (newVal) => {
//   if (newVal) {
//     nextTick(() => {
//       animateGlobalCoverage()
//     })
//   }
// })

onMounted(() => {
  startBannerTimer()
  
  nextTick(() => {
    animateBannerText()
    animateTextElements()
    animateProductCards()
  })
  
  if (pricingSectionRef.value) {
    pricingObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isPricingSectionVisible.value = true
          } else {
            isPricingSectionVisible.value = false
          }
        })
      },
      { threshold: 0.3 }
    )
    pricingObserver.observe(pricingSectionRef.value)
  }
  
  if (industrySolutionRef.value) {
    industrySolutionObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isIndustrySolutionVisible.value = true
          } else {
            isIndustrySolutionVisible.value = false
          }
        })
      },
      { threshold: 0.2 }
    )
    industrySolutionObserver.observe(industrySolutionRef.value)
  }
  
  if (globalCoverageRef.value) {
    globalCoverageObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isGlobalCoverageVisible.value = true
            coverageTitleChars.value = '安全合规，基础设施遍布全球'.split('')
            coverageDescChars.value = '包含主要国家和地区，云数据中心30+，储备带宽15T+'.split('')
            setTimeout(() => {
              isCoverageAnimating.value = true
            }, 100)
            setTimeout(() => {
              animateStatItems()
            }, 500)
            setTimeout(() => {
              animateGlobalCoverageText()
            }, 600)
          } else {
            isGlobalCoverageVisible.value = false
            isCoverageAnimating.value = false
            coverageTitleChars.value = []
            coverageDescChars.value = []
            
            const statItems = document.querySelectorAll('.stat-item-random')
            statItems.forEach((item) => {
              const statItem = item as HTMLElement
              const number = statItem.querySelector('.stat-number') as HTMLElement
              const label = statItem.querySelector('.stat-label') as HTMLElement
              
              if (number) {
                number.style.opacity = '0'
                number.style.transform = 'translateY(20px)'
              }
              
              if (label) {
                label.style.opacity = '0'
                label.style.transform = 'translateY(10px)'
              }
            })
            
            const textElements = globalCoverageRef.value.querySelectorAll('.animate-text')
            textElements.forEach((el) => {
              const textEl = el as HTMLElement
              textEl.style.opacity = '0'
            })
          }
        })
      },
      { threshold: 0.2 }
    )
    globalCoverageObserver.observe(globalCoverageRef.value)
  }
  
  if (faqSectionRef.value) {
    faqSectionObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            isFaqSectionVisible.value = true
            animateFaqSection()
          } else {
            isFaqSectionVisible.value = false
            
            const faqSection = faqSectionRef.value
            if (!faqSection) return
            
            const title = faqSection.querySelector('.faq-title') as HTMLElement
            const subtitle = faqSection.querySelector('.faq-subtitle') as HTMLElement
            const faqItems = faqSection.querySelectorAll('.faq-item-animate')
            
            if (title) {
              title.style.opacity = '0'
              title.style.transform = 'translateY(30px)'
            }
            
            if (subtitle) {
              subtitle.style.opacity = '0'
              subtitle.style.transform = 'translateY(20px)'
            }
            
            faqItems.forEach((item) => {
              const faqItem = item as HTMLElement
              const index = Array.from(faqItems).indexOf(item)
              faqItem.style.opacity = '0'
              faqItem.style.transform = `translateX(${index % 2 === 0 ? -30 : 30}px)`
            })
          }
        })
      },
      { threshold: 0.2 }
    )
    faqSectionObserver.observe(faqSectionRef.value)
  }
})

onUnmounted(() => {
  if (bannerTimer) clearInterval(bannerTimer)
  if (globalCoverageObserver && globalCoverageRef.value) {
    globalCoverageObserver.unobserve(globalCoverageRef.value)
  }
  if (faqSectionObserver && faqSectionRef.value) {
    faqSectionObserver.unobserve(faqSectionRef.value)
  }
})
</script>

<template>
  <div class="min-h-screen">
    <!-- Hero Section -->
    <section class="relative overflow-hidden pt-20 lg:pt-24">
      <div class="absolute inset-0">
        <transition-group name="fade">
          <div
            v-for="(banner, index) in banners"
            :key="index"
            v-show="currentBanner === index"
            class="absolute inset-0"
          >
            <video v-if="banner.video" :src="banner.video" autoplay loop muted playsinline class="w-full h-full object-cover">
              <img :src="banner.image" :alt="banner.title" class="w-full h-full object-cover" />
            </video>
            <img v-else :src="banner.image" :alt="banner.title" class="w-full h-full object-cover" />
            <div class="absolute inset-0 bg-gradient-to-r from-black/10 via-black/1 to-transparent dark:from-dark-600/80 dark:via-dark-600/60"></div>
          </div>
        </transition-group>
      </div>

      <button @click="prevBanner" class="absolute left-4 top-1/2 -translate-y-1/2 z-10 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center text-white transition-all">
        <ChevronLeft class="w-5 h-5" />
      </button>
      <button @click="nextBanner" class="absolute right-4 top-1/2 -translate-y-1/2 z-10 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-sm flex items-center justify-center text-white transition-all">
        <ChevronRight class="w-5 h-5" />
      </button>

      <div class="absolute bottom-8 left-1/2 -translate-x-1/2 z-10 flex gap-2">
        <button
          v-for="(_, index) in banners"
          :key="index"
          :class="['w-2.5 h-2.5 rounded-full transition-all duration-300', currentBanner === index ? 'bg-flame-500 w-8' : 'bg-white/50 hover:bg-white/80']"
          @click="currentBanner = index; resetBannerTimer()"
        ></button>
      </div>

      <div class="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-28">
        <div class="max-w-2xl">
          <div :key="currentBanner">
            <h1 class="text-4xl lg:text-5xl xl:text-6xl font-bold text-white leading-tight mb-6 banner-title">
              <span
                v-for="(char, index) in bannerTitleChars"
                :key="'title-' + index"
                :class="['inline-block char-type', isBannerAnimating ? 'animate' : '']"
                :style="{ animationDelay: `${index * 50}ms` }"
