  capabilityCards?: Array<{ title: string; desc: string }>
  securityItems?: string[]
  infrastructureItems?: string[]
}

interface Props {
  title: string
  layers: Layer[]
}

const props = defineProps<Props>()

const getBadgeClass = computed(() => (badgeColor: string) => {
  const colorMap: Record<string, string> = {
    'access': 'bg-green-500',
    'business': 'bg-blue-500',
    'capability': 'bg-amber-500',
    'security': 'bg-red-500',
    'infrastructure': 'bg-gray-500',
  }
  return colorMap[badgeColor] || 'bg-gray-500'
})

const getCardBgClass = computed(() => (badgeColor: string) => {
  const colorMap: Record<string, string> = {
    'access': 'bg-green-50 dark:bg-green-900/20',
    'business': 'bg-blue-50 dark:bg-blue-900/20',
    'capability': 'bg-amber-50 dark:bg-amber-900/20',
    'security': 'bg-red-50 dark:bg-red-900/20',
    'infrastructure': 'bg-gray-50 dark:bg-gray-800',
  }
  return colorMap[badgeColor] || 'bg-gray-50 dark:bg-gray-800'
})
</script>

