        <div class="layer-header">
          <div :class="['layer-badge', getBadgeClass(layer.badgeColor)]"></div>
          <span class="layer-title-text">{{ layer.title }}</span>
        </div>
        
        <div v-if="layer.id === 'capability'" class="layer-content capability-section">
