<script setup lang="ts">
import { ref, computed, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { ChevronLeft, ChevronRight, LayoutDashboard, Server, HardDrive, Cloud, Shield, Activity, BarChart3, Users, Settings, Plus, Search, Trash2, ShieldCheck, AlertTriangle, FileText, Clock, Cpu, HardDrive as Disk, Zap, Globe, Key, Bell, TrendingUp, Target, Eye, PieChart, LineChart, UserPlus, Lock, ClipboardList } from 'lucide-vue-next'

const route = useRoute()
const router = useRouter()
const collapsed = ref(false)
const activeSubKey = computed(() => {
  const path = route.path
  for (const [module, menus] of Object.entries(subMenus)) {
    if (path.startsWith('/console/' + module)) {
      const matched = menus.find(m => m.path === path)
      if (matched) return matched.key
    }
  }
  const module = currentModule.value
  const menus = subMenus[module]
  return menus && menus.length > 0 ? menus[0].key : ''
})

const subMenus: Record<string, { key: string; name: string; icon: any; path?: string }[]> = {
  dashboard: [
    { key: 'overview', name: '资源概览', icon: LayoutDashboard, path: '/console/dashboard' },
    { key: 'activity', name: '最近活动', icon: Clock, path: '/console/dashboard' },
    { key: 'quick', name: '快速操作', icon: Zap, path: '/console/dashboard' },
  ],
  ecs: [
    { key: 'instances', name: '实例列表', icon: Server, path: '/console/ecs' },
    { key: 'images', name: '镜像管理', icon: FileText, path: '/console/ecs' },
    { key: 'security-group', name: '安全组', icon: ShieldCheck, path: '/console/ecs' },
    { key: 'keypairs', name: '密钥对', icon: Key, path: '/console/ecs' },
    { key: 'snapshots', name: '快照管理', icon: FileText, path: '/console/ecs' },
  ],
  oss: [
    { key: 'buckets', name: '存储桶列表', icon: HardDrive, path: '/console/oss' },
    { key: 'files', name: '文件管理', icon: Search, path: '/console/oss' },
    { key: 'access', name: '访问控制', icon: ShieldCheck, path: '/console/oss' },
    { key: 'cors', name: '跨域设置', icon: Globe, path: '/console/oss' },
    { key: 'recycle', name: '回收站', icon: Trash2, path: '/console/oss' },
  ],
  cdn: [
    { key: 'domains', name: '域名管理', icon: Globe, path: '/console/cdn' },
    { key: 'cache', name: '缓存配置', icon: Disk, path: '/console/cdn' },
    { key: 'refresh', name: '刷新预热', icon: Zap, path: '/console/cdn' },
    { key: 'stats', name: '统计分析', icon: BarChart3, path: '/console/cdn' },
  ],
  security: [
    { key: 'ddos', name: 'DDoS防护', icon: Shield, path: '/console/security' },
    { key: 'waf', name: 'WAF防护', icon: ShieldCheck, path: '/console/security' },
    { key: 'host', name: '主机安全', icon: Cpu, path: '/console/security' },
    { key: 'vuln', name: '漏洞扫描', icon: AlertTriangle, path: '/console/security' },
  ],
  monitor: [
    { key: 'panel', name: '监控面板', icon: Activity, path: '/console/monitor' },
    { key: 'alerts', name: '告警策略', icon: Bell, path: '/console/monitor' },
    { key: 'history', name: '告警历史', icon: Clock, path: '/console/monitor' },
    { key: 'metrics', name: '指标管理', icon: LineChart, path: '/console/monitor' },
  ],
  analytics: [
    { key: 'business', name: '业务概览', icon: PieChart, path: '/console/analytics' },
    { key: 'users', name: '用户分析', icon: Users, path: '/console/analytics' },
    { key: 'traffic', name: '流量分析', icon: TrendingUp, path: '/console/analytics' },
    { key: 'reports', name: '报表中心', icon: FileText, path: '/console/analytics' },
  ],
  users: [
    { key: 'list', name: '用户列表', icon: Users, path: '/console/users' },
    { key: 'roles', name: '角色管理', icon: UserPlus, path: '/console/users' },
    { key: 'permissions', name: '权限配置', icon: Lock, path: '/console/users' },
    { key: 'audit', name: '操作日志', icon: ClipboardList, path: '/console/users' },
  ],
  settings: [
    { key: 'profile', name: '个人信息', icon: UserPlus, path: '/console/settings/profile' },
    { key: 'security', name: '安全设置', icon: Shield, path: '/console/settings/security' },
    { key: 'notification', name: '通知设置', icon: Bell, path: '/console/settings/notification' },
    { key: 'region', name: '地域设置', icon: Globe, path: '/console/settings/region' },
  ],
}

const currentModule = computed(() => {
  const path = route.path
  if (path.startsWith('/console/dashboard')) return 'dashboard'
  if (path.startsWith('/console/ecs')) return 'ecs'
  if (path.startsWith('/console/oss')) return 'oss'
  if (path.startsWith('/console/cdn')) return 'cdn'
  if (path.startsWith('/console/security')) return 'security'
  if (path.startsWith('/console/monitor')) return 'monitor'
  if (path.startsWith('/console/analytics')) return 'analytics'
  if (path.startsWith('/console/users')) return 'users'
  if (path.startsWith('/console/settings')) return 'settings'
  return 'dashboard'
})

const currentSubMenus = computed(() => subMenus[currentModule.value] || [])

const moduleTitle: Record<string, string> = {
  dashboard: '控制台',
  ecs: '云服务器',
  oss: '对象存储',
  cdn: 'CDN加速',
  security: '安全防护',
  monitor: '监控告警',
  analytics: '数据分析',
  users: '用户管理',
  settings: '账号设置',
}

watch(currentModule, () => {
})

const handleSubMenuClick = (item: { path?: string; key: string }) => {
  if (item.path) {
    router.push(item.path)
  }
}

const toggleSidebar = () => {
  collapsed.value = !collapsed.value
}

defineExpose({
  collapsed,
  toggleSidebar
})
</script>

<template>
  <aside
    :class="[
      'h-full bg-[#202020] text-white flex flex-col transition-all duration-300 flex-shrink-0',
      collapsed ? 'w-16' : 'w-[199px]'
    ]"
  >
    <div class="px-5 pt-4 pb-3 border-b border-gray-800 flex-shrink-0">
      <span v-if="!collapsed" class="text-lg font-bold text-white">{{ moduleTitle[currentModule] }}</span>
    </div>

    <nav class="flex-1 py-4 overflow-y-auto">
      <ul class="space-y-1 px-2">
        <li v-for="item in currentSubMenus" :key="item.key">
          <button
            @click="handleSubMenuClick(item)"
            :class="[
              'w-full flex items-center gap-3 px-3 py-2.5 transition-all duration-200',
              activeSubKey === item.key
                ? 'bg-flame-500 text-white shadow-lg shadow-flame-500/25'
                : 'text-gray-300 hover:bg-gray-800 hover:text-white'
            ]"
          >
            <component :is="item.icon" class="w-5 h-5 flex-shrink-0" />
            <span v-if="!collapsed" class="text-sm font-medium whitespace-nowrap">{{ item.name }}</span>
          </button>
        </li>
      </ul>
    </nav>
  </aside>
</template>
