<script setup lang="ts">
import { ref } from 'vue'
import { Activity, Bell, Server, HardDrive, Cpu, Clock, Plus, BellOff } from 'lucide-vue-next'

const metrics = ref([
  { name: 'CPU使用率', value: '45%', trend: 12, unit: '', icon: Cpu },
  { name: '内存使用', value: '68%', trend: 5, unit: '', icon: HardDrive },
  { name: '磁盘I/O', value: '120', unit: 'MB/s', trend: -8, icon: HardDrive },
  { name: '网络流量', value: '240', unit: 'Mbps', trend: 25, icon: Activity },
])

const alerts = ref([
  { id: 1, type: 'cpu', level: 'warning', message: 'ECS-001 CPU使用率超过80%', time: '2分钟前', status: 'active' },
  { id: 2, type: 'memory', level: 'critical', message: 'ECS-002 内存使用率超过90%', time: '5分钟前', status: 'active' },
  { id: 3, type: 'disk', level: 'info', message: 'OSS存储空间已使用85%', time: '1小时前', status: 'resolved' },
])

const getAlertColor = (level: string) => {
  switch (level) {
    case 'critical':
      return 'bg-red-100 text-red-600'
    case 'warning':
      return 'bg-yellow-100 text-yellow-600'
    default:
      return 'bg-blue-100 text-blue-600'
  }
}

const getStatusColor = (status: string) => {
  return status === 'active' ? 'bg-red-500' : 'bg-green-500'
}
</script>

<template>
  <div class="p-6 space-y-6">
    <div class="flex items-center justify-between">
      <div>
        <h1 class="text-2xl font-bold text-gray-900">监控告警</h1>
        <p class="text-gray-500 mt-1">实时监控资源状态和告警信息</p>
      </div>
      <button class="flame-btn flex items-center gap-2">
        <Plus class="w-4 h-4" />
        <span class="text-sm font-medium">创建告警规则</span>
      </button>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      <div
        v-for="(metric, index) in metrics"
        :key="index"
        class="bg-white border border-gray-100 p-6 hover:shadow-lg transition-all"
      >
        <div class="flex items-start justify-between">
          <div class="w-12 h-12 bg-blue-50 flex items-center justify-center">
            <component :is="metric.icon" class="w-6 h-6 text-blue-500" />
          </div>
          <div
            :class="[
              'flex items-center gap-1 px-2 py-1 text-xs font-medium',
              metric.trend >= 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
            ]"
          >
            <span>{{ metric.trend >= 0 ? '+' : '' }}{{ metric.trend }}%</span>
          </div>
        </div>
        <div class="mt-4">
          <p class="text-sm text-gray-500">{{ metric.name }}</p>
          <div class="flex items-baseline gap-1 mt-1">
            <span class="text-3xl font-bold text-gray-900">{{ metric.value }}</span>
            <span class="text-sm text-gray-500">{{ metric.unit }}</span>
          </div>
        </div>
      </div>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div class="lg:col-span-2 bg-white border border-gray-100 p-6">
        <div class="flex items-center justify-between mb-6">
          <h2 class="text-lg font-semibold text-gray-900">资源使用趋势</h2>
          <div class="flex items-center gap-2">
            <button class="px-3 py-1 text-sm font-medium text-flame-500 bg-flame-50">实时</button>
            <button class="px-3 py-1 text-sm text-gray-500 hover:bg-gray-100 transition-colors">1小时</button>
            <button class="px-3 py-1 text-sm text-gray-500 hover:bg-gray-100 transition-colors">24小时</button>
          </div>
        </div>
        <div class="h-64 flex items-end gap-2">
          <div
            v-for="i in 24"
            :key="i"
            class="flex-1 bg-gradient-to-t from-flame-500 to-orange-400"
            :style="{ height: `${20 + Math.random() * 60}%` }"
          ></div>
        </div>
        <div class="flex justify-between mt-3 text-xs text-gray-400">
          <span>00:00</span>
          <span>06:00</span>
          <span>12:00</span>
          <span>18:00</span>
          <span>24:00</span>
        </div>
      </div>

      <div class="bg-white border border-gray-100 overflow-hidden">
        <div class="px-6 py-4 border-b border-gray-100">
          <div class="flex items-center justify-between">
            <h2 class="text-lg font-semibold text-gray-900">告警通知</h2>
            <span class="flex items-center gap-1 text-sm text-red-500">
              <Bell class="w-4 h-4" />
              {{ alerts.filter(a => a.status === 'active').length }}
            </span>
          </div>
        </div>
        <div class="divide-y divide-gray-50 max-h-80 overflow-y-auto">
          <div
            v-for="alert in alerts"
            :key="alert.id"
            class="px-6 py-4 hover:bg-gray-50 transition-colors"
          >
            <div class="flex items-start gap-3">
              <div :class="['w-8 h-8 flex items-center justify-center flex-shrink-0', getAlertColor(alert.level)]">
                <Bell v-if="alert.status === 'active'" class="w-4 h-4" />
                <BellOff v-else class="w-4 h-4" />
              </div>
              <div class="flex-1 min-w-0">
                <div class="flex items-center gap-2">
                  <span :class="['px-2 py-0.5 text-xs font-medium', getAlertColor(alert.level)]">
                    {{ alert.level === 'critical' ? '严重' : alert.level === 'warning' ? '警告' : '信息' }}
                  </span>
                  <span :class="['w-2 h-2', getStatusColor(alert.status)]"></span>
                </div>
                <p class="text-sm text-gray-900 mt-1">{{ alert.message }}</p>
                <div class="flex items-center gap-1 mt-1 text-xs text-gray-400">
                  <Clock class="w-3 h-3" />
                  {{ alert.time }}
                </div>
              </div>
            </div>
          </div>
        </div>
        <div class="px-6 py-3 bg-gray-50 border-t border-gray-100">
          <button class="w-full text-sm text-flame-500 hover:text-flame-600 font-medium">查看全部告警</button>
        </div>
      </div>
    </div>
  </div>
</template>
