<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { useRoute } from 'vue-router'
import { Settings, User, Bell, Shield, Globe, Save, ChevronRight, UserCircle } from 'lucide-vue-next'
import { API_BASE_URL, API_ENDPOINTS } from '@/config/api'

const route = useRoute()

const activeTab = computed(() => {
  const path = route.path
  if (path.includes('/profile')) return 'profile'
  if (path.includes('/security')) return 'security'
  if (path.includes('/notification')) return 'notification'
  if (path.includes('/region')) return 'region'
  return 'profile'
})

const tabTitles: Record<string, string> = {
  profile: '个人信息',
  security: '安全设置',
  notification: '通知设置',
  region: '地域设置',
}

const profileForm = ref({
  name: '',
  company: '',
  department: '',
})

const notificationSettings = ref({
  email: true,
  sms: false,
  push: true,
  weeklyReport: true,
})

const securitySettings = ref({
  twoFactor: true,
  loginAlert: true,
  sessionTimeout: 30,
})

const regionSettings = ref({
  defaultRegion: '华北-北京',
  language: '中文',
  timezone: 'UTC+8',
})

const regions = ['华北-北京', '华东-上海', '华南-广州', '西南-成都']
const languages = ['中文', 'English']
const timezones = ['UTC+8', 'UTC+7', 'UTC+9']

const fetchProfile = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return

  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'GET',
      headers: {
        'uid': uid,
        'token': token,
      },
    })
    const data = await res.json()
    if (data.code === 0 && data.data) {
      profileForm.value.name = data.data.name || ''
      profileForm.value.company = data.data.company || ''
      profileForm.value.department = data.data.department || ''
    }
  } catch (e) {
    console.error(e)
  }
}

const saveProfile = async () => {
  const uid = localStorage.getItem('uid')
  const token = localStorage.getItem('token')
  if (!uid || !token) return

  const params = new URLSearchParams()
  params.append('name', profileForm.value.name)
  params.append('company', profileForm.value.company)
  params.append('department', profileForm.value.department)

  try {
    const res = await fetch(`${API_BASE_URL}${API_ENDPOINTS.user.info}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'uid': uid,
        'token': token,
      },
      body: params.toString(),
    })
    const data = await res.json()
    if (data.code === 0) {
      alert('保存成功')
    } else {
      alert(data.echo || '保存失败')
    }
  } catch (e) {
    console.error(e)
    alert('保存失败')
  }
}

onMounted(() => {
  if (activeTab.value === 'profile') {
    fetchProfile()
  }
})
</script>

<template>
  <div>
    <div class="bg-white border-b border-gray-100 px-6 py-5">
      <h1 class="text-2xl font-bold text-gray-900">{{ tabTitles[activeTab] }}</h1>
      <p v-if="activeTab === 'profile'" class="text-gray-500 mt-1">管理您的账号信息</p>
      <p v-else-if="activeTab === 'security'" class="text-gray-500 mt-1">配置账号安全选项</p>
      <p v-else-if="activeTab === 'notification'" class="text-gray-500 mt-1">管理您的通知偏好</p>
      <p v-else-if="activeTab === 'region'" class="text-gray-500 mt-1">设置您的地域和语言</p>
    </div>

    <div class="p-6 space-y-6">
      <div class="bg-white border border-gray-100 overflow-hidden">
        <div class="p-6">
        <div v-if="activeTab === 'profile'">
          <div class="flex items-center gap-6 mb-8">
            <div class="relative">
              <div class="w-20 h-20 bg-gradient-to-br from-flame-500 to-orange-500 flex items-center justify-center">
                <UserCircle class="w-10 h-10 text-white" />
              </div>
              <button class="absolute -bottom-1 -right-1 w-8 h-8 bg-white border-2 border-gray-200 flex items-center justify-center hover:border-flame-500 transition-colors">
                <Settings class="w-4 h-4 text-gray-500" />
              </button>
            </div>
            <div>
              <h3 class="text-lg font-semibold text-gray-900">{{ profileForm.name || '未设置' }}</h3>
              <p class="text-sm text-gray-500">个人账号</p>
            </div>
          </div>

          <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">姓名</label>
              <input
                v-model="profileForm.name"
                type="text"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              />
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">公司</label>
              <input
                v-model="profileForm.company"
                type="text"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              />
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">部门</label>
              <input
                v-model="profileForm.department"
                type="text"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              />
            </div>
          </div>
        </div>

        <div v-else-if="activeTab === 'notification'">
          <div class="space-y-4">
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">邮件通知</h4>
                <p class="text-sm text-gray-500">接收重要通知邮件</p>
              </div>
              <button
                @click="notificationSettings.email = !notificationSettings.email"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  notificationSettings.email ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    notificationSettings.email ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">短信通知</h4>
                <p class="text-sm text-gray-500">接收重要通知短信</p>
              </div>
              <button
                @click="notificationSettings.sms = !notificationSettings.sms"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  notificationSettings.sms ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    notificationSettings.sms ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">推送通知</h4>
                <p class="text-sm text-gray-500">接收浏览器推送通知</p>
              </div>
              <button
                @click="notificationSettings.push = !notificationSettings.push"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  notificationSettings.push ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    notificationSettings.push ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">周报订阅</h4>
                <p class="text-sm text-gray-500">每周接收使用报告</p>
              </div>
              <button
                @click="notificationSettings.weeklyReport = !notificationSettings.weeklyReport"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  notificationSettings.weeklyReport ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    notificationSettings.weeklyReport ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
          </div>
        </div>

        <div v-else-if="activeTab === 'security'">
          <div class="space-y-4">
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">双因素认证</h4>
                <p class="text-sm text-gray-500">登录时需要额外验证</p>
              </div>
              <button
                @click="securitySettings.twoFactor = !securitySettings.twoFactor"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  securitySettings.twoFactor ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    securitySettings.twoFactor ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
            <div class="flex items-center justify-between p-4 bg-gray-50">
              <div>
                <h4 class="font-medium text-gray-900">登录提醒</h4>
                <p class="text-sm text-gray-500">异地登录时发送提醒</p>
              </div>
              <button
                @click="securitySettings.loginAlert = !securitySettings.loginAlert"
                :class="[
                  'relative w-12 h-6 transition-colors',
                  securitySettings.loginAlert ? 'bg-flame-500' : 'bg-gray-300'
                ]"
              >
                <span
                  :class="[
                    'absolute top-1 w-4 h-4 bg-white transition-transform',
                    securitySettings.loginAlert ? 'translate-x-7' : 'translate-x-1'
                  ]"
                ></span>
              </button>
            </div>
            <div class="p-4 bg-gray-50">
              <div class="flex items-center justify-between mb-3">
                <div>
                  <h4 class="font-medium text-gray-900">会话超时时间</h4>
                  <p class="text-sm text-gray-500">无操作自动登出时间</p>
                </div>
              </div>
              <div class="flex items-center gap-4">
                <select
                  v-model="securitySettings.sessionTimeout"
                  class="px-4 py-2 bg-white border border-gray-200 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
                >
                  <option :value="15">15分钟</option>
                  <option :value="30">30分钟</option>
                  <option :value="60">1小时</option>
                  <option :value="120">2小时</option>
                </select>
              </div>
            </div>
            <button class="w-full p-4 bg-gray-50 flex items-center justify-between hover:bg-gray-100 transition-colors">
              <div>
                <h4 class="font-medium text-gray-900">修改密码</h4>
                <p class="text-sm text-gray-500">定期更换密码以保证安全</p>
              </div>
              <ChevronRight class="w-5 h-5 text-gray-400" />
            </button>
          </div>
        </div>

        <div v-else-if="activeTab === 'region'">
          <div class="space-y-4">
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">默认地域</label>
              <select
                v-model="regionSettings.defaultRegion"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              >
                <option v-for="region in regions" :key="region" :value="region">{{ region }}</option>
              </select>
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">语言</label>
              <select
                v-model="regionSettings.language"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              >
                <option v-for="lang in languages" :key="lang" :value="lang">{{ lang }}</option>
              </select>
            </div>
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-2">时区</label>
              <select
                v-model="regionSettings.timezone"
                class="w-full px-4 py-3 bg-white border border-gray-300 focus:outline-none focus:ring-2 focus:ring-flame-500/20 focus:border-flame-500"
              >
                <option v-for="tz in timezones" :key="tz" :value="tz">{{ tz }}</option>
              </select>
            </div>
          </div>
        </div>

        <div class="mt-8 flex justify-end">
          <button v-if="activeTab === 'profile'" @click="saveProfile" class="flame-btn flex items-center gap-2">
            <Save class="w-4 h-4" />
            <span class="text-sm font-medium">保存设置</span>
          </button>
          <button v-else class="flame-btn flex items-center gap-2">
            <Save class="w-4 h-4" />
            <span class="text-sm font-medium">保存设置</span>
          </button>
        </div>
      </div>
    </div>
    </div>
  </div>
</template>
